  1→import { useState, useMemo } from 'react';
  2→import { useLoanData } from './hooks/useLoanData';
  3→import { useAmortization } from './hooks/useAmortization';
  4→import type { PrePayment, AmortizationResult } from './types/loan';
  5→import { calculateAmortization } from './utils/amortization';
  6→import { LoanForm } from './components/LoanForm';
  7→import { PrePaymentList } from './components/PrePaymentList';
  8→import { RateChangeList } from './components/RateChangeList';
  9→import { SummaryCards } from './components/SummaryCards';
 10→import { AmortizationTable } from './components/AmortizationTable';
 11→import { WhatIfSimulator } from './components/WhatIfSimulator';
 12→import { BalanceChart } from './components/charts/BalanceChart';
 13→import { PrincipalInterestChart } from './components/charts/PrincipalInterestChart';
 14→import { ComparisonChart } from './components/charts/ComparisonChart';
 15→import { CumulativeInterestChart } from './components/charts/CumulativeInterestChart';
 16→import { PaymentBreakupChart } from './components/charts/PaymentBreakupChart';
 17→import { YearlySummaryChart } from './components/charts/YearlySummaryChart';
 18→
 19→function App() {
 20→  const {
 21→    loan, setLoan,
 22→    prePayments, addPrePayment, removePrePayment,
 23→    rateChanges, addRateChange, removeRateChange,
 24→  } = useLoanData();
 25→  const { summary, error } = useAmortization(loan, prePayments, rateChanges);
 26→
 27→  // Simulator state (not persisted)
 28→  const [plannedPPs, setPlannedPPs] = useState<PrePayment[]>([]);
 29→
 30→  const simulatedResult = useMemo<AmortizationResult | null>(() => {
 31→    if (!loan || plannedPPs.length === 0) return null;
 32→    const allPPs = [...prePayments, ...plannedPPs];
 33→    return calculateAmortization(loan, allPPs, rateChanges);
 34→  }, [loan, prePayments, rateChanges, plannedPPs]);
 35→
 36→  // Use simulated schedule for charts/table when active
 37→  const activeResult = simulatedResult ?? summary?.withPrePayments ?? null;
 38→
 39→  return (
 40→    <div className="min-h-screen bg-gray-50">
 41→      <header className="border-b border-gray-200 bg-white">
 42→        <div className="mx-auto max-w-7xl px-4 py-4">
 43→          <h1 className="text-2xl font-bold text-gray-900">Loan Analyser</h1>
 44→          <p className="text-sm text-gray-500">
 45→            Visualise your loan, add pre-payments, and see how much you save
 46→          </p>
 47→        </div>
 48→      </header>
 49→
 50→      <main className="mx-auto max-w-7xl px-4 py-6 space-y-6">
 51→        <LoanForm loan={loan} onSubmit={setLoan} />
 52→
 53→        {error && (
 54→          <div className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
 55→            {error}
 56→          </div>
 57→        )}
 58→
 59→        {loan && (
 60→          <>
 61→            <PrePaymentList
 62→              prePayments={prePayments}
 63→              onAdd={addPrePayment}
 64→              onRemove={removePrePayment}
 65→            />
 66→            <RateChangeList
 67→              rateChanges={rateChanges}
 68→              onAdd={addRateChange}
 69→              onRemove={removeRateChange}
 70→            />
 71→          </>
 72→        )}
 73→
 74→        {summary && loan && (
 75→          <>
 76→            <WhatIfSimulator
 77→              plannedPPs={plannedPPs}
 78→              onAdd={(pp) => setPlannedPPs((prev) => [...prev, pp])}
 79→              onRemove={(id) => setPlannedPPs((prev) => prev.filter((p) => p.id !== id))}
 80→              currentResult={summary.withPrePayments}
 81→              simulatedResult={simulatedResult}
 82→            />
 83→
 84→            <SummaryCards summary={summary} loan={loan} />
 85→
 86→            {simulatedResult && (
 87→              <div className="rounded-lg border border-amber-300 bg-amber-50 px-4 py-2 text-sm text-amber-800 flex items-center gap-2">
 88→                <span className="font-semibold">Simulation active</span>
 89→                &mdash; Charts and table below reflect your planned pre-payments.
 90→                <button
 91→                  onClick={() => setPlannedPPs([])}
 92→                  className="ml-auto text-amber-600 hover:text-amber-800 font-medium underline"
 93→                >
 94→                  Clear simulation
 95→                </button>
 96→              </div>
 97→            )}
 98→
 99→            <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
100→              <BalanceChart
101→                summary={summary}
102→                simulatedResult={simulatedResult}
103→              />
104→              <CumulativeInterestChart
105→                summary={summary}
106→                simulatedResult={simulatedResult}
107→              />
108→            </div>
109→
110→            <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
111→              <ComparisonChart
112→                summary={summary}
113→                simulatedResult={simulatedResult}
114→              />
115→              <PaymentBreakupChart summary={summary} />
116→            </div>
117→
118→            <PrincipalInterestChart
119→              schedule={activeResult!.schedule}
120→              isSimulated={!!simulatedResult}
121→            />
122→
123→            <YearlySummaryChart
124→              schedule={activeResult!.schedule}
125→              isSimulated={!!simulatedResult}
126→            />
127→
128→            <AmortizationTable
129→              schedule={activeResult!.schedule}
130→              isSimulated={!!simulatedResult}
131→              actualScheduleLength={summary.withPrePayments.schedule.length}
132→              plannedPPMonths={new Set(
133→                plannedPPs.map((pp) => pp.date.substring(0, 7))
134→              )}
135→            />
136→          </>
137→        )}
138→      </main>
139→    </div>
140→  );
141→}
142→
143→export default App;
144→

 1→import { format, parseISO } from 'date-fns';
 2→
 3→export function formatCurrency(amount: number): string {
 4→  return new Intl.NumberFormat('en-IN', {
 5→    style: 'currency',
 6→    currency: 'INR',
 7→    maximumFractionDigits: 0,
 8→  }).format(amount);
 9→}
10→
11→export function formatCurrencyShort(amount: number): string {
12→  if (amount >= 1_00_00_000) {
13→    return `${(amount / 1_00_00_000).toFixed(2)} Cr`;
14→  }
15→  if (amount >= 1_00_000) {
16→    return `${(amount / 1_00_000).toFixed(2)} L`;
17→  }
18→  return formatCurrency(amount);
19→}
20→
21→export function formatDate(dateStr: string): string {
22→  return format(parseISO(dateStr), 'MMM yyyy');
23→}
24→
25→export function formatDateFull(dateStr: string): string {
26→  return format(parseISO(dateStr), 'dd MMM yyyy');
27→}
