  1→import {
  2→  LineChart,
  3→  Line,
  4→  XAxis,
  5→  YAxis,
  6→  CartesianGrid,
  7→  Tooltip,
  8→  Legend,
  9→  ResponsiveContainer,
 10→  ReferenceLine,
 11→} from 'recharts';
 12→import { format } from 'date-fns';
 13→import type { LoanSummary, AmortizationResult } from '../../types/loan';
 14→import { formatCurrency, formatDate } from '../../utils/formatters';
 15→
 16→interface Props {
 17→  summary: LoanSummary;
 18→  simulatedResult?: AmortizationResult | null;
 19→}
 20→
 21→export function BalanceChart({ summary, simulatedResult }: Props) {
 22→  const { withPrePayments, withoutPrePayments } = summary;
 23→
 24→  const currentMonthKey = format(new Date(), 'yyyy-MM');
 25→
 26→  const maxLen = Math.max(
 27→    withPrePayments.schedule.length,
 28→    withoutPrePayments.schedule.length,
 29→    simulatedResult?.schedule.length ?? 0
 30→  );
 31→
 32→  let currentMonthIndex: number | null = null;
 33→
 34→  const data = Array.from({ length: maxLen }, (_, i) => {
 35→    const dateStr =
 36→      withoutPrePayments.schedule[i]?.date ??
 37→      withPrePayments.schedule[i]?.date ??
 38→      simulatedResult?.schedule[i]?.date ??
 39→      '';
 40→    const monthKey = dateStr.substring(0, 7);
 41→    if (monthKey === currentMonthKey) {
 42→      currentMonthIndex = i + 1;
 43→    }
 44→    const entry: Record<string, number | string> = {
 45→      month: i + 1,
 46→      label: dateStr ? formatDate(dateStr) : '',
 47→      withoutPP: withoutPrePayments.schedule[i]?.closingBalance ?? 0,
 48→      withPP: withPrePayments.schedule[i]?.closingBalance ?? 0,
 49→    };
 50→    if (simulatedResult) {
 51→      entry.simulated = simulatedResult.schedule[i]?.closingBalance ?? 0;
 52→    }
 53→    return entry;
 54→  });
 55→
 56→  return (
 57→    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
 58→      <h3 className="mb-4 text-lg font-semibold text-gray-900">
 59→        Outstanding Balance Over Time
 60→      </h3>
 61→      <ResponsiveContainer width="100%" height={350}>
 62→        <LineChart data={data}>
 63→          <CartesianGrid strokeDasharray="3 3" />
 64→          <XAxis
 65→            dataKey="month"
 66→            label={{ value: 'Month', position: 'insideBottom', offset: -5 }}
 67→          />
 68→          <YAxis
 69→            tickFormatter={(v) => formatCurrency(v)}
 70→            width={100}
 71→          />
 72→          <Tooltip
 73→            formatter={(value: number) => formatCurrency(value)}
 74→            labelFormatter={(_: string, payload: Array<{ payload?: { label?: string } }>) => payload?.[0]?.payload?.label || ''}
 75→          />
 76→          <Legend />
 77→          {currentMonthIndex !== null && (
 78→            <ReferenceLine
 79→              x={currentMonthIndex}
 80→              stroke="#2563eb"
 81→              strokeWidth={2}
 82→              strokeDasharray="4 4"
 83→              label={{ value: 'Now', position: 'top', fill: '#2563eb', fontWeight: 'bold' }}
 84→            />
 85→          )}
 86→          <Line
 87→            type="monotone"
 88→            dataKey="withoutPP"
 89→            name="Original Schedule"
 90→            stroke="#94a3b8"
 91→            strokeWidth={2}
 92→            dot={false}
 93→          />
 94→          <Line
 95→            type="monotone"
 96→            dataKey="withPP"
 97→            name="Actual (with adjustments)"
 98→            stroke="#2563eb"
 99→            strokeWidth={2}
100→            dot={false}
101→          />
102→          {simulatedResult && (
103→            <Line
104→              type="monotone"
105→              dataKey="simulated"
106→              name="Simulated (what-if)"
107→              stroke="#f59e0b"
108→              strokeWidth={2}
109→              strokeDasharray="6 3"
110→              dot={false}
111→            />
112→          )}
113→        </LineChart>
114→      </ResponsiveContainer>
115→    </div>
116→  );
117→}
