 1→import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
 2→import type { LoanSummary } from '../../types/loan';
 3→import { formatCurrency } from '../../utils/formatters';
 4→
 5→interface Props {
 6→  summary: LoanSummary;
 7→}
 8→
 9→const COLORS = ['#22c55e', '#ef4444'];
10→
11→export function PaymentBreakupChart({ summary }: Props) {
12→  const { withPrePayments: wp } = summary;
13→  const principalPaid = wp.totalAmountPaid - wp.totalInterest;
14→
15→  const data = [
16→    { name: 'Principal', value: Math.round(principalPaid) },
17→    { name: 'Interest', value: Math.round(wp.totalInterest) },
18→  ];
19→
20→  const total = data[0].value + data[1].value;
21→
22→  const renderLabel = ({
23→    cx,
24→    cy,
25→    midAngle,
26→    innerRadius,
27→    outerRadius,
28→    index,
29→  }: {
30→    cx: number;
31→    cy: number;
32→    midAngle: number;
33→    innerRadius: number;
34→    outerRadius: number;
35→    index: number;
36→  }) => {
37→    const RADIAN = Math.PI / 180;
38→    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
39→    const x = cx + radius * Math.cos(-midAngle * RADIAN);
40→    const y = cy + radius * Math.sin(-midAngle * RADIAN);
41→    const pct = ((data[index].value / total) * 100).toFixed(1);
42→
43→    return (
44→      <text
45→        x={x}
46→        y={y}
47→        fill="white"
48→        textAnchor="middle"
49→        dominantBaseline="central"
50→        fontWeight="bold"
51→        fontSize={14}
52→      >
53→        {pct}%
54→      </text>
55→    );
56→  };
57→
58→  return (
59→    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
60→      <h3 className="mb-4 text-lg font-semibold text-gray-900">
61→        Payment Breakup
62→      </h3>
63→      <ResponsiveContainer width="100%" height={350}>
64→        <PieChart>
65→          <Pie
66→            data={data}
67→            cx="50%"
68→            cy="50%"
69→            outerRadius={130}
70→            dataKey="value"
71→            labelLine={false}
72→            label={renderLabel}
73→          >
74→            {data.map((_, index) => (
75→              <Cell key={index} fill={COLORS[index]} />
76→            ))}
77→          </Pie>
78→          <Tooltip formatter={(value: number) => formatCurrency(value)} />
79→        </PieChart>
80→      </ResponsiveContainer>
81→      <div className="mt-2 flex justify-center gap-6 text-sm">
82→        <span className="flex items-center gap-1.5">
83→          <span className="inline-block h-3 w-3 rounded-full bg-green-500" />
84→          Principal: {formatCurrency(principalPaid)}
85→        </span>
86→        <span className="flex items-center gap-1.5">
87→          <span className="inline-block h-3 w-3 rounded-full bg-red-500" />
88→          Interest: {formatCurrency(wp.totalInterest)}
89→        </span>
90→      </div>
91→    </div>
92→  );
93→}
