 1→import {
 2→  BarChart,
 3→  Bar,
 4→  XAxis,
 5→  YAxis,
 6→  CartesianGrid,
 7→  Tooltip,
 8→  Legend,
 9→  ResponsiveContainer,
10→} from 'recharts';
11→import type { AmortizationRow } from '../../types/loan';
12→import { formatCurrency } from '../../utils/formatters';
13→
14→interface Props {
15→  schedule: AmortizationRow[];
16→  isSimulated?: boolean;
17→}
18→
19→export function YearlySummaryChart({ schedule, isSimulated }: Props) {
20→  const yearMap = new Map<string, { interest: number; principal: number }>();
21→
22→  for (const row of schedule) {
23→    const year = row.date.substring(0, 4);
24→    const existing = yearMap.get(year) || { interest: 0, principal: 0 };
25→    existing.interest += row.interestComponent;
26→    existing.principal += row.principalComponent + row.prePayment;
27→    yearMap.set(year, existing);
28→  }
29→
30→  const data = Array.from(yearMap.entries()).map(([year, vals]) => ({
31→    year,
32→    interest: Math.round(vals.interest),
33→    principal: Math.round(vals.principal),
34→  }));
35→
36→  return (
37→    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
38→      <h3 className="mb-4 text-lg font-semibold text-gray-900">
39→        Yearly Summary
40→        {isSimulated && (
41→          <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
42→        )}
43→      </h3>
44→      <ResponsiveContainer width="100%" height={350}>
45→        <BarChart data={data}>
46→          <CartesianGrid strokeDasharray="3 3" />
47→          <XAxis dataKey="year" />
48→          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
49→          <Tooltip
50→            formatter={(value: number) => formatCurrency(value)}
51→            labelFormatter={(label) => `Year ${label}`}
52→          />
53→          <Legend />
54→          <Bar dataKey="principal" name="Principal + Prepayment" fill="#22c55e" />
55→          <Bar dataKey="interest" name="Interest" fill="#ef4444" />
56→        </BarChart>
57→      </ResponsiveContainer>
58→    </div>
59→  );
60→}
