 1→import type { LoanInput, LoanSummary } from '../types/loan';
 2→import { formatCurrency, formatDate } from '../utils/formatters';
 3→
 4→interface Props {
 5→  summary: LoanSummary;
 6→  loan: LoanInput;
 7→}
 8→
 9→export function SummaryCards({ summary, loan }: Props) {
10→  const { withPrePayments: wp, withoutPrePayments: wop } = summary;
11→
12→  // Loan progress: how many months completed based on current date
13→  const now = new Date();
14→  const nowKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
15→  let monthsCompleted = 0;
16→  for (const row of wp.schedule) {
17→    if (row.date.substring(0, 7) <= nowKey) {
18→      monthsCompleted = row.month;
19→    } else {
20→      break;
21→    }
22→  }
23→  const principalRepaid = monthsCompleted > 0
24→    ? loan.principal - (wp.schedule[monthsCompleted - 1]?.closingBalance ?? 0)
25→    : 0;
26→  const progressPct = ((principalRepaid / loan.principal) * 100).toFixed(1);
27→
28→  const cards = [
29→    {
30→      label: 'Total Interest',
31→      value: formatCurrency(wp.totalInterest),
32→      sub: `Original: ${formatCurrency(wop.totalInterest)}`,
33→      color: 'bg-red-50 border-red-200',
34→    },
35→    {
36→      label: 'Total Amount Paid',
37→      value: formatCurrency(wp.totalAmountPaid),
38→      sub: `Original: ${formatCurrency(wop.totalAmountPaid)}`,
39→      color: 'bg-blue-50 border-blue-200',
40→    },
41→    {
42→      label: 'Loan Closure Date',
43→      value: formatDate(wp.closureDate),
44→      sub: `Original: ${formatDate(wop.closureDate)}`,
45→      color: 'bg-purple-50 border-purple-200',
46→    },
47→    {
48→      label: 'Interest Saved',
49→      value: formatCurrency(summary.interestSaved),
50→      sub: `${((summary.interestSaved / wop.totalInterest) * 100).toFixed(1)}% reduction`,
51→      color: 'bg-green-50 border-green-200',
52→    },
53→    {
54→      label: 'Months Saved',
55→      value: `${summary.monthsSaved} months`,
56→      sub: `${wp.totalMonths} vs ${wop.totalMonths} months`,
57→      color: 'bg-amber-50 border-amber-200',
58→    },
59→    {
60→      label: 'Interest-to-Principal',
61→      value: `${((wp.totalInterest / loan.principal) * 100).toFixed(1)}%`,
62→      sub: `Original: ${((wop.totalInterest / loan.principal) * 100).toFixed(1)}%`,
63→      color: 'bg-orange-50 border-orange-200',
64→    },
65→    {
66→      label: 'Effective Cost',
67→      value: `${(wp.totalAmountPaid / loan.principal).toFixed(2)}x`,
68→      sub: `You pay ${(wp.totalAmountPaid / loan.principal).toFixed(2)}x the borrowed amount`,
69→      color: 'bg-cyan-50 border-cyan-200',
70→    },
71→    {
72→      label: 'Loan Progress',
73→      value: `${progressPct}%`,
74→      sub: `${monthsCompleted} months completed out of ${wp.totalMonths}`,
75→      color: 'bg-emerald-50 border-emerald-200',
76→    },
77→  ];
78→
79→  return (
80→    <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
81→      {cards.map((card) => (
82→        <div
83→          key={card.label}
84→          className={`rounded-xl border p-4 ${card.color}`}
85→        >
86→          <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
87→            {card.label}
88→          </p>
89→          <p className="mt-1 text-xl font-bold text-gray-900">{card.value}</p>
90→          <p className="mt-1 text-xs text-gray-500">{card.sub}</p>
91→        </div>
92→      ))}
93→    </div>
94→  );
95→}
