  1→import { useRef, useEffect } from 'react';
  2→import { format } from 'date-fns';
  3→import type { AmortizationRow } from '../types/loan';
  4→import { formatCurrency, formatDate } from '../utils/formatters';
  5→
  6→interface Props {
  7→  schedule: AmortizationRow[];
  8→  isSimulated?: boolean;
  9→  actualScheduleLength?: number;
 10→  plannedPPMonths?: Set<string>;
 11→}
 12→
 13→function getCurrentMonthKey(): string {
 14→  return format(new Date(), 'yyyy-MM');
 15→}
 16→
 17→export function AmortizationTable({
 18→  schedule,
 19→  isSimulated,
 20→  actualScheduleLength,
 21→  plannedPPMonths,
 22→}: Props) {
 23→  const currentMonthKey = getCurrentMonthKey();
 24→  const currentRowRef = useRef<HTMLTableRowElement>(null);
 25→
 26→  useEffect(() => {
 27→    if (currentRowRef.current) {
 28→      currentRowRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
 29→    }
 30→  }, [schedule]);
 31→
 32→  // Detect if rates change across the schedule
 33→  const hasRateChanges = schedule.length > 1 &&
 34→    schedule.some((row, i) => i > 0 && row.annualRate !== schedule[i - 1].annualRate);
 35→
 36→  return (
 37→    <div className="rounded-xl border border-gray-200 bg-white shadow-sm">
 38→      <div className="p-6 pb-0">
 39→        <h2 className="text-lg font-semibold text-gray-900">
 40→          Amortization Schedule
 41→          {isSimulated && (
 42→            <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
 43→          )}
 44→        </h2>
 45→        <p className="text-sm text-gray-500 mt-1">
 46→          {schedule.length} months
 47→          {isSimulated && actualScheduleLength && actualScheduleLength !== schedule.length && (
 48→            <span className="text-amber-600">
 49→              {' '}(was {actualScheduleLength} months)
 50→            </span>
 51→          )}
 52→        </p>
 53→      </div>
 54→      <div className="overflow-x-auto p-4">
 55→        <table className="w-full text-left text-sm">
 56→          <thead>
 57→            <tr className="border-b border-gray-200 text-gray-600">
 58→              <th className="pb-2 pr-3 font-medium">#</th>
 59→              <th className="pb-2 pr-3 font-medium">Date</th>
 60→              {hasRateChanges && (
 61→                <th className="pb-2 pr-3 font-medium text-right">Rate</th>
