              Interest: {formatCurrency(wp.totalInterest)}
            </div>
          </div>
        </div>
      </div>

      {/* Yearly Summary */}
      <div style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Yearly Summary</h3>
        <BarChart width={CHART_W} height={CHART_H} data={yearlyData}>
