import { useRef, useState, useCallback } from 'react';

export function useExportPdf() {
  const reportRef = useRef<HTMLDivElement>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const exportPdf = useCallback(async (filename?: string) => {
    const el = reportRef.current;
    if (!el || isGenerating) return;

    setIsGenerating(true);
    try {
      const html2pdf = (await import('html2pdf.js')).default;
      const date = new Date().toISOString().split('T')[0];
      const name = filename ?? `loan-report-${date}.pdf`;

      // Make visible for html2canvas (offscreen but in layout)
      el.style.display = 'block';
      el.style.position = 'absolute';
      el.style.left = '0';
      el.style.top = '0';
      el.style.zIndex = '-9999';
      el.style.opacity = '0';
      el.style.pointerEvents = 'none';

      // Wait for Recharts SVGs to render
      await new Promise((r) => setTimeout(r, 500));

      await html2pdf()
        .set({
          margin: 10,
          filename: name,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true, logging: false },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          pagebreak: { mode: ['avoid-all', 'css', 'legacy'] },
        })
        .from(el)
        .save();
    } finally {
      // Hide again
      el.style.display = 'none';
      setIsGenerating(false);
    }
  }, [isGenerating]);

  return { reportRef, isGenerating, exportPdf };
}

